SELECT song_id, SUM(likes) AS total_likes
FROM social_media_metrics
GROUP BY song_id;

SELECT AVG(engagement_rate) AS average_engagement_rate
FROM social_media_metrics
WHERE metric_date BETWEEN '2023-12-01' AND '2023-12-31';

SELECT 
    (SELECT COUNT(DISTINCT song_id) FROM songs) AS total_songs,
    (SELECT COUNT(DISTINCT artist_id) FROM artists) AS total_artists;

SELECT title 
FROM songs 
WHERE play_count = (SELECT MAX(play_count) FROM songs);

SELECT trend_source
FROM trending_songs
WHERE song_id = 1;

SELECT COUNT(DISTINCT song_id) 
FROM song_ranks 
WHERE chart_id = (SELECT chart_id FROM charts WHERE chart_name = 'Billboard Hot 100');
